1	<!DOCTYPE html>
2	<html lang="en">
3	<head>
4	  <meta charset="UTF-8" />
5	  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
6	  <title>Demo User</title>
7	  <style>
8	    :root {
9	      --bg: #09090b;
10	      --surface: #131316;
11	      --text: #ededf0;
12	      --muted: #8b8b96;
13	      --accent: #5eead4;
14	      --accent-2: #a78bfa;
15	      --border: #232329;
16	    }
17	
18	    * {
19	      margin: 0;
20	      padding: 0;
21	      box-sizing: border-box;
22	    }
23	
24	    html {
25	      scroll-behavior: smooth;
26	    }
27	
28	    ::selection {
29	      background: rgba(94, 234, 212, 0.25);
30	    }
31	
32	    body {
33	      font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
34	      background: var(--bg);
35	      color: var(--text);
36	      line-height: 1.6;
37	      -webkit-font-smoothing: antialiased;
38	    }
39	
40	    .container {
41	      max-width: 720px;
42	      margin: 0 auto;
43	      padding: 0 24px;
44	    }
45	
46	    /* Header / hero */
47	    header {
48	      position: relative;
49	      padding: 96px 0 64px;
50	    }
51	
52	    header::before {
53	      content: "";
54	      position: absolute;
55	      top: -160px;
56	      left: -120px;
57	      width: 480px;
58	      height: 480px;
59	      background: radial-gradient(circle, rgba(94, 234, 212, 0.08), transparent 70%);
60	      pointer-events: none;
61	    }
62	
63	    .avatar {
64	      width: 88px;
65	      height: 88px;
66	      border-radius: 50%;
67	      background: linear-gradient(135deg, var(--accent), var(--accent-2));
68	      display: flex;
69	      align-items: center;
70	      justify-content: center;
71	      font-size: 32px;
72	      font-weight: 700;
73	      color: var(--bg);
74	      margin-bottom: 24px;
75	      box-shadow: 0 0 40px rgba(94, 234, 212, 0.25);
76	    }
77	
78	    h1 {
79	      font-size: 40px;
80	      font-weight: 700;
81	      letter-spacing: -0.02em;
82	      margin-bottom: 8px;
83	    }
84	
85	    .tagline {
86	      font-size: 20px;
87	      color: var(--muted);
88	      margin-bottom: 24px;
89	    }
90	
91	    .intro {
92	      font-size: 17px;
93	      color: var(--text);
94	      max-width: 60ch;
95	    }
96	
97	    /* Sections */
98	    section {
99	      padding: 40px 0;
100	      border-top: 1px solid var(--border);
101	    }
102	
103	    h2 {
104	      font-size: 14px;
105	      font-weight: 600;
106	      text-transform: uppercase;
107	      letter-spacing: 0.08em;
108	      color: var(--muted);
109	      margin-bottom: 24px;
110	    }
111	
112	    /* Work / projects */
113	    .section-note {
114	      font-size: 16px;
115	      color: var(--muted);
116	      max-width: 60ch;
117	    }
118	
119	    .section-note a {
120	      color: var(--accent);
121	      text-decoration: none;
122	    }
123	
124	    .section-note a:hover {
125	      text-decoration: underline;
126	    }
127	
128	    /* Skills */
129	    .skills {
130	      display: grid;
131	      grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
132	      gap: 16px;
133	    }
134	
135	    .skill {
136	      background: var(--surface);
137	      border: 1px solid var(--border);
138	      border-radius: 12px;
139	      padding: 20px 24px;
140	    }
141	
142	    .skill h3 {
143	      font-size: 16px;
144	      font-weight: 600;
145	      margin-bottom: 4px;
146	    }
147	
148	    .skill p {
149	      font-size: 14px;
150	      color: var(--muted);
151	    }
152	
153	    /* Testimonials */
154	    .testimonial-card {
155	      background: var(--surface);
156	      border: 1px solid var(--border);
157	      border-radius: 12px;
158	      padding: 24px;
159	      margin-bottom: 16px;
160	    }
161	
162	    .testimonial-card:last-child {
163	      margin-bottom: 0;
164	    }
165	
166	    .testimonial-card blockquote {
167	      font-size: 16px;
168	      font-style: italic;
169	      margin-bottom: 12px;
170	    }
171	
172	    .testimonial-card cite {
173	      font-size: 14px;
174	      font-style: normal;
175	      color: var(--muted);
176	    }
177	
178	    /* Contact links */
179	    .links {
180	      display: flex;
181	      flex-wrap: wrap;
182	      gap: 12px;
183	    }
184	
185	    .links a {
186	      display: inline-block;
187	      padding: 10px 18px;
188	      border: 1px solid var(--border);
189	      border-radius: 999px;
190	      color: var(--text);
191	      text-decoration: none;
192	      font-size: 15px;
193	      transition: border-color 0.15s ease, color 0.15s ease;
194	    }
195	
196	    .links a:hover {
197	      border-color: var(--accent);
198	      color: var(--accent);
199	    }
200	
201	    footer {
202	      padding: 40px 0 64px;
203	      border-top: 1px solid var(--border);
204	      color: var(--muted);
205	      font-size: 14px;
206	    }
207	
208	    @media (max-width: 480px) {
209	      header {
210	        padding: 64px 0 48px;
211	      }
212	
213	      h1 {
214	        font-size: 32px;
215	      }
216	
217	      .tagline {
218	        font-size: 18px;
219	      }
220	    }
221	  </style>
222	</head>
223	<body>
224	  <div class="container">
225	    <header>
226	      <div class="avatar">AK</div>
227	      <h1>Demo User</h1>
228	      <p class="tagline">Software engineer &amp; builder</p>
229	      <p class="intro">
230	        Hi, I'm Demo User. I build software and enjoy turning ideas into simple,
231	        well-crafted tools. This is my corner of the internet — a place for
232	        what I'm working on and how to reach me.
233	      </p>
234	    </header>
235	
236	    <section>
237	      <h2>What I'm working on</h2>
238	      <p class="section-note">
239	        I'm always building something — new projects will land here soon.
240	        In the meantime, you can find my work on
241	        <a href="https://github.com/" target="_blank" rel="noopener">GitHub</a>.
242	      </p>
243	    </section>
244	
245	    <section>
246	      <h2>Skills</h2>
247	      <div class="skills">
248	        <div class="skill">
249	          <h3>Web Development</h3>
250	          <p>Building responsive, accessible sites with modern HTML, CSS, and JavaScript.</p>
251	        </div>
252	        <div class="skill">
253	          <h3>Backend &amp; APIs</h3>
254	          <p>Designing and shipping reliable services, from data models to deployment.</p>
255	        </div>
256	        <div class="skill">
257	          <h3>Developer Tooling</h3>
258	          <p>Automating workflows and crafting small tools that make teams faster.</p>
259	        </div>
260	      </div>
261	    </section>
262	
263	    <section>
264	      <h2>Testimonials</h2>
265	      <div class="testimonial-card">
266	        <blockquote>&ldquo;Demo User turned a vague idea into a working product in weeks. Clear communication, clean code, and no surprises.&rdquo;</blockquote>
267	        <cite>&mdash; Jordan Lee, Product Manager</cite>
268	      </div>
269	      <div class="testimonial-card">
270	        <blockquote>&ldquo;One of the most reliable engineers I've worked with. The tooling they built saved our team hours every single week.&rdquo;</blockquote>
271	        <cite>&mdash; Sam Rivera, Engineering Lead</cite>
272	      </div>
273	    </section>
274	
275	    <section>
276	      <h2>Get in touch</h2>
277	      <div class="links">
278	        <a href="mailto:<email>">Email</a>
279	        <a href="https://github.com/" target="_blank" rel="noopener">GitHub</a>
280	        <a href="https://www.linkedin.com/" target="_blank" rel="noopener">LinkedIn</a>
281	      </div>
282	    </section>
283	
284	    <footer>
285	      &copy; 2026 Demo User
286	    </footer>
287	  </div>
288	</body>
289	</html>
